import { MakeLogicType, actions, events, kea, path } from 'kea'
import { loaders } from 'kea-loaders'

import api from 'lib/api'
import { lemonToast } from 'lib/lemon-ui/LemonToast/LemonToast'


export interface ConnectedApp {
    id: string
    name: string
    logo_uri: string | null
    scopes: string[]
    authorized_at: string
    is_verified: boolean
    is_first_party: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface connectedAppsLogicValues {
    connectedApps: ConnectedApp[];
    connectedAppsLoading: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface connectedAppsLogicActions {
    loadConnectedApps: () => any;
    loadConnectedAppsFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadConnectedAppsSuccess: (connectedApps: ConnectedApp[], payload?: any) => {
        connectedApps: ConnectedApp[];
        payload?: any;
    };
    revokeApp: (id: string) => {
        id: string;
    };
    revokeAppFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    revokeAppSuccess: (connectedApps: ConnectedApp[], payload?: {
        id: string;
    }) => {
        connectedApps: ConnectedApp[];
        payload?: {
            id: string;
        };
    };
}

export type connectedAppsLogicType = MakeLogicType<connectedAppsLogicValues, connectedAppsLogicActions>;

export const connectedAppsLogic = kea<connectedAppsLogicType>([
    path(['scenes', 'settings', 'user', 'connectedAppsLogic']),

    actions({
        revokeApp: (id: string) => ({ id }),
    }),

    loaders(({ values }) => ({
        connectedApps: [
            [] as ConnectedApp[],
            {
                loadConnectedApps: async () => {
                    return await api.get('api/oauth/connected-apps/')
                },
                revokeApp: async ({ id }) => {
                    await api.create(`api/oauth/connected-apps/${id}/revoke/`)
                    lemonToast.success('App access revoked')
                    return values.connectedApps.filter((app) => app.id !== id)
                },
            },
        ],
    })),

    events(({ actions }) => ({
        afterMount: () => actions.loadConnectedApps(),
    })),
])
